// // This comment suggests that the toggle output will be set to HIGH on every rising edge of the clock, regardless of the pulse input.
module top_module(
    input      clk,
    input      rst,
    input      pulse,
    output reg toggle
);always @ (posedge clk or posedge rst)
        if (rst)
            toggle <= 0;
        else
            toggle <= toggle ^ pulse;

endmodule
